4560 /// Fold comparisons of reduce.or/reduce.and with reduce.umax/reduce.umin
4561 /// based on cost, preserving the comparison semantics.
4562 ///
4563 /// We use two fundamental properties for each pair:
4564 ///
4565 ///   1. or(X) == 0 <=> umax(X) == 0
4566 ///   2. or(X) == 1 <=> umax(X) == 1
4567 ///   3. sign(or(X)) == sign(umax(X))
4568 ///
4569 ///   1. and(X) == -1 <=> umin(X) == -1
4570 ///   2. and(X) == -2 <=> umin(X) == -2
4571 ///   3. sign(and(X)) == sign(umin(X))
4572 ///
4573 /// From these we can infer the following transformations:
4574 ///   a. or(X) ==/!= 0   <-> umax(X) ==/!= 0
4575 ///   b. or(X) s< 0      <-> umax(X) s< 0
4576 ///   c. or(X) s> -1     <-> umax(X) s> -1
4577 ///   d. or(X) s< 1      <-> umax(X) s< 1
4578 ///   e. or(X) ==/!= 1   <-> umax(X) ==/!= 1
4579 ///   f. or(X) s< 2      <-> umax(X) s< 2
4580 ///   g. and(X) ==/!= -1 <-> umin(X) ==/!= -1
4581 ///   h. and(X) s< 0     <-> umin(X) s< 0
4582 ///   i. and(X) s> -1    <-> umin(X) s> -1
4583 ///   j. and(X) s> -2    <-> umin(X) s> -2
4584 ///   k. and(X) ==/!= -2 <-> umin(X) ==/!= -2
4585 ///   l. and(X) s> -3    <-> umin(X) s> -3
