4694 /// Returns true if this ShuffleVectorInst eventually feeds into a
4695 /// vector reduction intrinsic (e.g., vector_reduce_add) by only following
4696 /// chains of shuffles and binary operators (in any combination/order).
4697 /// The search does not go deeper than the given Depth.
4698 static bool feedsIntoVectorReduction(ShuffleVectorInst *SVI) {
4699   constexpr unsigned MaxVisited = 32;
4700   SmallPtrSet<Instruction *, 8> Visited;
4701   SmallVector<Instruction *, 4> WorkList;
4702   bool FoundReduction = false;
4703 
4704   WorkList.push_back(SVI);
4705   while (!WorkList.empty()) {
4706     Instruction *I = WorkList.pop_back_val();
4707     for (User *U : I->users()) {
4708       auto *UI = cast<Instruction>(U);
4709       if (!UI || !Visited.insert(UI).second)
4710         continue;
4711       if (Visited.size() > MaxVisited)
4712         return false;
4713       if (auto *II = dyn_cast<IntrinsicInst>(UI)) {
4714         // More than one reduction reached
4715         if (FoundReduction)
4716           return false;
4717         switch (II->getIntrinsicID()) {
4718         case Intrinsic::vector_reduce_add:
4719         case Intrinsic::vector_reduce_mul:
4720         case Intrinsic::vector_reduce_and:
4721         case Intrinsic::vector_reduce_or:
4722         case Intrinsic::vector_reduce_xor:
4723         case Intrinsic::vector_reduce_smin:
4724         case Intrinsic::vector_reduce_smax:
4725         case Intrinsic::vector_reduce_umin:
4726         case Intrinsic::vector_reduce_umax:
4727           FoundReduction = true;
4728           continue;
4729         default:
4730           return false;
4731         }
4732       }
4733 
4734       if (!isa<BinaryOperator>(UI) && !isa<ShuffleVectorInst>(UI))
4735         return false;
4736 
4737       WorkList.emplace_back(UI);
4738     }
4739   }
4740   return FoundReduction;
4741 }
